SELECT id, user_id AS userId, user_name AS userName, product_id AS productId, product_name AS productName, product_category AS productCategory, product_category AS category, unit_price AS unitPrice, purchase_time AS purchaseTime, purchase_quantity AS quantity, consumption_amount AS amount, user_city AS userCity, user_city AS city, user_name AS customer, DATE(purchase_time) AS date, '已完成' AS status, consumption_amount AS consumptionAmount, user_gender AS userGender, user_age AS userAge FROM domestic_orders
AND (id LIKE CONCAT('%', #{keyword}, '%') OR user_name LIKE CONCAT('%', #{keyword}, '%') OR product_name LIKE CONCAT('%', #{keyword}, '%'))
AND product_category = #{category}
ORDER BY purchase_time DESC LIMIT #{offset}, #{size}

SELECT COUNT(*) FROM domestic_orders
AND (id LIKE CONCAT('%', #{keyword}, '%') OR user_name LIKE CONCAT('%', #{keyword}, '%') OR product_name LIKE CONCAT('%', #{keyword}, '%'))
AND product_category = #{category}

SELECT COUNT(*) AS order_count, COALESCE(SUM(consumption_amount), 0) AS amount FROM domestic_orders
AND (id LIKE CONCAT('%', #{keyword}, '%') OR user_name LIKE CONCAT('%', #{keyword}, '%') OR product_name LIKE CONCAT('%', #{keyword}, '%'))
AND product_category = #{category}
